import React, { useEffect, useRef } from 'react';
import lottie from 'lottie-web';

const LottieAnimation = () => {
  const animationRef = useRef(null);

  useEffect(() => {
    if (!animationRef.current) {
      // Initialize Lottie animation if it hasn't been initialized yet
      animationRef.current = lottie.loadAnimation({
        container: document.getElementById('alienAnimation'),
        renderer: 'svg',
        loop: false,
        autoplay: true,
        animationData: require('../resources/animation_lkuowbyo.json'), // Replace with the path to your Lottie animation JSON file
      });
    }
  }, []);

  return (
    <div id="alienAnimation" style={{ width: '300px', height: '300px' }}></div>
  );
};

export default LottieAnimation;
